package ir.tahamohamadi.publication; import ir.tahamohamadi.common.domain.LanguageCode; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import jakarta.persistence.*; import lombok.*; import java.util.UUID;
@Entity @Table(name="publication_translation") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class PublicationTranslation extends AuditedSoftDeletableEntity { @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="publication_id",nullable=false) private Publication publication; @Enumerated(EnumType.STRING) @Column(name="language_code",nullable=false,length=2) private LanguageCode languageCode; @Column(nullable=false) private String title; @Column(nullable=false) private String slug; @Column(name="abstract_text",columnDefinition="text") private String abstractText; @Column(name="authors_display",columnDefinition="text") private String authorsDisplay; @Column(name="venue_display",columnDefinition="text") private String venueDisplay; @Column(name="seo_title") private String seoTitle; @Column(name="seo_description") private String seoDescription; private PublicationTranslation(UUID id,Publication publication,LanguageCode language,String title,String slug,String abstractText,String authorsDisplay,String venueDisplay,String seoTitle,String seoDescription,java.time.Instant at){initialize(id,at);this.publication=java.util.Objects.requireNonNull(publication,"publication");this.languageCode=java.util.Objects.requireNonNull(language,"language");update(title,slug,abstractText,authorsDisplay,venueDisplay,seoTitle,seoDescription,at);} public static PublicationTranslation create(UUID id,Publication publication,LanguageCode language,String title,String slug,String abstractText,String authorsDisplay,String venueDisplay,String seoTitle,String seoDescription,java.time.Instant at){return new PublicationTranslation(id,publication,language,title,slug,abstractText,authorsDisplay,venueDisplay,seoTitle,seoDescription,at);} public void update(String title,String slug,String abstractText,String authorsDisplay,String venueDisplay,String seoTitle,String seoDescription,java.time.Instant at){this.title=requireNonBlank(title,"title");this.slug=requireNonBlank(slug,"slug");this.abstractText=abstractText;this.authorsDisplay=authorsDisplay;this.venueDisplay=venueDisplay;this.seoTitle=seoTitle;this.seoDescription=seoDescription;updatedAt=java.util.Objects.requireNonNull(at,"at");} }
